import React from "react";
import { Link } from "react-router-dom";

<div className="flex flex-col gap-4">
  <Link to="/">NewFeed</Link>
  <Link to="/settings">Setting</Link>
</div>


export default function Sidebar({ onNavigate }) {
  return (
    <div className="fixed top-[140px] left-0 flex flex-col items-center bg-[#88BCF8] w-[88px] py-[25px] px-[23px] gap-[28px] z-40 rounded-tr-[20px] rounded-br-[20px] shadow-md">
      {/* Trang chủ */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/yrrmpwtt_expires_30_days.png"
        className="w-[42px] h-[42px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("home")}
      />

      {/* Bạn bè */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/31c1kzbw_expires_30_days.png"
        className="w-[42px] h-[37px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("friends")}
      />

      {/* Thông báo */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/06392zkx_expires_30_days.png"
        className="w-[42px] h-[37px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("notifications")}
      />

            {/* 📰 NewFeed (Bảng tin) */}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/jrlw9206_expires_30_days.png"
        className="w-[42px] h-[42px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("newfeed")}
      />

      {/* profile*/}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/6tc1xyl6_expires_30_days.png"
        className="w-[42px] h-[42px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("profile")}
      />

      {/* setting*/}
      <img
        src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/7sbt7zog_expires_30_days.png"
        className="w-[42px] h-[42px] cursor-pointer hover:scale-110 transition"
        onClick={() => onNavigate("setting")}
      />
    </div>
    
  );
}
